ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/streamingservice#>
PREFIX p: <http://ambrosia.example.org/streamingservice/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?award_name ?film WHERE {
  ?award a :Award .
  ?award p:Award_Name ?award_name .
  ?award p:Film ?film .
  ?award p:Presenter ?presenter_f .
  FILTER(STR(?presenter_f) = STR("Zack Snyder"))
} }
  full: { SELECT ?award_name ?winning_category ?film WHERE {
  ?award a :Award .
  ?award p:Award_Name ?award_name .
  ?award p:Winning_Category ?winning_category .
  ?award p:Film ?film .
  ?award p:Presenter ?presenter_f .
  FILTER(STR(?presenter_f) = STR("Zack Snyder"))
} }
  component_2: { SELECT ?winning_category ?film WHERE {
  ?award a :Award .
  ?award p:Winning_Category ?winning_category .
  ?award p:Film ?film .
  ?award p:Presenter ?presenter_f .
  FILTER(STR(?presenter_f) = STR("Zack Snyder"))
} }
}

